arguments.command:
cd /tmp/sv-ff437c9a9092406080af1b39cdc9f641/simple-single-project && dotnet list MyApp/MyApp.csproj package --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)
bp = {p['id']: p['resolvedVersion'] for p in b['projects'][0]['frameworks'][0]['topLevelPackages']}
ap = {p['id']: p['resolvedVersion'] for p in a['projects'][0]['frameworks'][0]['topLevelPackages']}
if bp == ap:
    print('✅ All packages resolve to identical versions before and after conversion.')
else:
    for k in set(list(bp.keys()) + list(ap.keys())):
        bv, av = bp.get(k, 'MISSING'), ap.get(k, 'MISSING')
        if bv != av: print(f'⚠️  {k}: {bv} → {av}')
"

